diata')?><br><small><?=atenea_e($c['fecha_limite']?:'Sin límite')?></small></td><td><?=$c['obligatorio']?'Obligatorio':'Opcional'?> · <?=number_format((float)$c['peso_progreso'],2)?>%</td><td><a class="btn btn-sm btn-outline-primary" href="<?=docenteUrl('contenido_editar.php',['id'=>$c['id']])?>">Editar</a><?php if($c['archivo_relpath']):?> <a class="btn btn-sm btn-outline-secondary" href="<?=atenea_url('src/academico/archivo.php?tipo=contenido&id='.$c['id'])?>">Archivo</a><?php endif;?></td></tr><?php endforeach;?><?php if(!$filas):?><tr><td colspan="6" class="text-center py-5">No hay contenidos.</td></tr><?php endif;?></tbody></table></div></div></div><?php docentePie();
